#!/usr/bin/env bash
set -euo pipefail

cd /workspace/maui

# Idempotent: skip if already applied
if grep -q "## Prerequisites" .github/skills/issue-triage/SKILL.md 2>/dev/null; then
    echo "Patch already applied."
    exit 0
fi

# Write .github/skills/issue-triage/SKILL.md
base64 -d << 'B64EOF' > .github/skills/issue-triage/SKILL.md

B64EOF

# Write .github/skills/issue-triage/scripts/init-triage-session.ps1
base64 -d << 'B64EOF' > .github/skills/issue-triage/scripts/init-triage-session.ps1

B64EOF

# Write .github/skills/issue-triage/scripts/query-issues.ps1
base64 -d << 'B64EOF' > .github/skills/issue-triage/scripts/query-issues.ps1

B64EOF

echo "SKILL.md, init-triage-session.ps1, and query-issues.ps1 updated"
echo "Patch applied successfully."
